#!/usr/bin/env python3\n\"\"\"Command-line interface for Telemetry Hub daemon.\"\"\"\n\nimport click\nimport json\nimport subprocess\nimport sys\nimport time\nfrom pathlib import Path\nfrom .server import TelemetryServer\n\n\n@click.group()\ndef cli():\n    \"\"\"Star Citizen Telemetry Hub.\"\"\"\n    pass\n\n\n@cli.group()\ndef daemon():\n    \"\"\"Manage the telemetry daemon.\"\"\"\n    pass\n\n\n@daemon.command()\n@click.option('--host', default='127.0.0.1', help='Listen host')\n@click.option('--port', default=5050, help='TCP server port')\n@click.option('--broadcast-port', default=5555, help='UDP broadcast port')\n@click.option('--dbox-port', default=33740, help='D-BOX input port')\ndef start(host, port, broadcast_port, dbox_port):\n    \"\"\"Start the telemetry daemon.\"\"\"\n    click.echo(f\"🎮 Starting Telemetry Hub daemon...\")\n    click.echo(f\"   D-BOX input: {host}:{dbox_port}\")\n    click.echo(f\"   TCP server: {host}:{port}\")\n    click.echo(f\"   UDP broadcast: {host}:{broadcast_port}\")\n    click.echo()\n    \n    server = TelemetryServer(\n        host=host,\n        tcp_port=port,\n        broadcast_port=broadcast_port,\n        dbox_port=dbox_port\n    )\n    \n    try:\n        server.start()\n    except KeyboardInterrupt:\n        click.echo(\"\\n🛑 Shutting down...\")\n        server.stop()\n        sys.exit(0)\n\n\n@daemon.command()\ndef status():\n    \"\"\"Check daemon status.\"\"\"\n    import socket\n    \n    try:\n        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\n        sock.settimeout(1)\n        result = sock.connect_ex(('127.0.0.1', 5050))\n        sock.close()\n        \n        if result == 0:\n            click.echo(\"✅ Daemon is running on port 5050\")\n        else:\n            click.echo(\"❌ Daemon is not running\")\n            sys.exit(1)\n    except Exception as e:\n        click.echo(f\"❌ Error checking status: {e}\")\n        sys.exit(1)\n\n\n@daemon.command()\ndef stop():\n    \"\"\"Stop the running daemon.\"\"\"\n    import socket\n    \n    try:\n        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\n        sock.connect(('127.0.0.1', 5050))\n        sock.send(b'{\"command\": \"shutdown\"}')\n        sock.close()\n        click.echo(\"🛑 Shutdown signal sent\")\n    except ConnectionRefusedError:\n        click.echo(\"❌ Daemon is not running\")\n        sys.exit(1)\n    except Exception as e:\n        click.echo(f\"❌ Error: {e}\")\n        sys.exit(1)\n\n\n@cli.command()\ndef ping():\n    \"\"\"Test daemon connectivity.\"\"\"\n    import socket\n    \n    try:\n        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\n        sock.settimeout(2)\n        sock.connect(('127.0.0.1', 5050))\n        \n        # Send ping command\n        sock.send(b'{\"command\": \"ping\"}')\n        \n        # Wait for response\n        response = sock.recv(1024)\n        sock.close()\n        \n        result = json.loads(response.decode())\n        if result.get('status') == 'ok':\n            click.echo(f\"✅ {result.get('message')}\")\n        else:\n            click.echo(f\"❌ Unexpected response: {result}\")\n            sys.exit(1)\n    except ConnectionRefusedError:\n        click.echo(\"❌ Cannot connect to daemon (is it running?)\")\n        sys.exit(1)\n    except Exception as e:\n        click.echo(f\"❌ Error: {e}\")\n        sys.exit(1)\n\n\ndef main():\n    \"\"\"Entry point.\"\"\"\n    cli()\n\n\nif __name__ == '__main__':\n    main()\n"